import{c as o,Q as d,j as a,m as t}from"./chunks/framework.iD28w_5a.js";const h=JSON.parse('{"title":"028d-sync-safety-2 · 同步安全","description":"","frontmatter":{"title":"028d-sync-safety-2 · 同步安全"},"headers":[],"relativePath":"hands-on/028d-sync-safety-2.md","filePath":"hands-on/028d-sync-safety-2.md","lastUpdated":1779686691000}'),c={name:"hands-on/028d-sync-safety-2.md"};function l(r,e,s,n,p,i){return d(),a("div",null,[...e[0]||(e[0]=[t(`<h1 id="_028d-2-全面加锁——三层分级策略" tabindex="-1">028d-2: 全面加锁——三层分级策略 <a class="header-anchor" href="#_028d-2-全面加锁——三层分级策略" aria-label="Permalink to &quot;028d-2: 全面加锁——三层分级策略&quot;">​</a></h1><h2 id="导语" tabindex="-1">导语 <a class="header-anchor" href="#导语" aria-label="Permalink to &quot;导语&quot;">​</a></h2><p>上一章我们完成了自旋锁和 RAII 守卫的基建。现在到了真正动手的时候——把锁加到内核的每一个共享数据结构上。这听起来像是一个体力活，但实际上需要非常仔细的策略规划。加少了会留下数据竞争的隐患，加多了会影响性能甚至引入死锁。更关键的是，不同组件面临的风险等级不同，需要的保护手段也不同——有些需要完整的 IrqGuard（关中断+自旋锁），有些只需要普通 Guard，还有些用 <code>std::atomic</code> 就够了。</p><p>完成这一章后，内核的所有共享数据结构都将受到保护，支持在抢占式多任务和中断环境下安全运行。</p><p>前置要求：上一章的 Spinlock、IrqGuard、InterruptGuard 实现必须完成。</p><h2 id="概念精讲" tabindex="-1">概念精讲 <a class="header-anchor" href="#概念精讲" aria-label="Permalink to &quot;概念精讲&quot;">​</a></h2><h3 id="三层分级策略" tabindex="-1">三层分级策略 <a class="header-anchor" href="#三层分级策略" aria-label="Permalink to &quot;三层分级策略&quot;">​</a></h3><p>在开始逐个组件加锁之前，我们先制定一个分级策略。不是所有共享数据都需要同等强度的保护，过度保护只会增加复杂度和死锁风险。</p><p><strong>TIER 0——核心分配器</strong>（数据竞争必然崩溃）：PMM、Heap、Scheduler 运行队列。这些是内核最底层的共享资源，所有内核线程都在用，而且它们内部的数据结构（位图、空闲链表、环形数组）在并发操作下会立刻损坏。必须用最强的保护——Scheduler 用 IrqGuard（因为它的运行队列在中断上下文中被操作），PMM 和 Heap 用普通 Guard（它们的操作不会在中断处理程序中直接执行，但在递归调用时需要注意锁的拆分）。</p><p><strong>TIER 1——高频共享计数器</strong>（竞争导致数据不一致）：PIT 的 tick 计数器、Scheduler 的时间片计数器、TaskBuilder 的 TID 和栈地址分配器。这些变量被频繁读写，但单次不一致不会导致系统崩溃。使用 <code>std::atomic</code> 的 <code>MemoryOrder::Relaxed</code> 就足够了——我们只需要保证读写的原子性，不需要强排序。</p><p><strong>TIER 2——中等风险组件</strong>（并发访问频率较低）：File 的 offset、FDTable、VMM 的 map/unmap、全局 mount 表。这些在正常的内核操作中不太可能被并发访问，但在多线程环境下仍然需要保护。使用普通 Spinlock Guard 即可。</p><h3 id="锁的拆分-为什么需要-locked-版本" tabindex="-1">锁的拆分：为什么需要 _locked 版本 <a class="header-anchor" href="#锁的拆分-为什么需要-locked-版本" aria-label="Permalink to &quot;锁的拆分：为什么需要 _locked 版本&quot;">​</a></h3><p>一个常见陷阱是&quot;在持有锁的情况下调用也会获取同一个锁的函数&quot;。PMM 就是一个典型例子：<code>alloc_pages</code> 需要分配多个连续页，内部逻辑和 <code>alloc_page</code> 几乎一样。如果 <code>alloc_pages</code> 持有锁然后调用 <code>alloc_page</code>（也会尝试获取同一个锁），立刻死锁——自旋锁不支持递归。</p><p>解决方案是把核心逻辑拆成一个不需要锁的内部版本（<code>alloc_page_locked</code>），公共版本只负责获取锁然后调用内部版本。这样 <code>alloc_pages</code> 持有锁后可以安全地调用 <code>_locked</code> 版本。</p><h2 id="动手实现" tabindex="-1">动手实现 <a class="header-anchor" href="#动手实现" aria-label="Permalink to &quot;动手实现&quot;">​</a></h2><h3 id="step-1-pmm-加锁" tabindex="-1">Step 1: PMM 加锁 <a class="header-anchor" href="#step-1-pmm-加锁" aria-label="Permalink to &quot;Step 1: PMM 加锁&quot;">​</a></h3><p><strong>目标</strong>: 保护物理内存管理器的位图操作。</p><p><strong>设计思路</strong>: PMM 的核心是一个位图，<code>alloc_page</code> 需要&quot;查找第一个空闲位 + 设为已用&quot;这两步是原子的——如果两步之间被打断，另一个线程可能看到同一个空闲位并认为它可用。我们把原来的 <code>alloc_page</code> 拆分为两部分：一个不带锁的内部版本 <code>alloc_page_locked</code>（做实际工作），和一个公共版本 <code>alloc_page</code>（获取 Spinlock 后调用内部版本）。<code>free_page</code> 做同样的拆分。</p><p><code>alloc_pages</code>（分配连续多页）需要特殊处理：它获取锁后，如果 count==1，直接调用 <code>_locked</code> 版本（不能调用公共版本，否则死锁）；如果 count&gt;1，在持锁状态下直接操作位图。<code>free_pages</code> 同理——获取锁后循环调用 <code>_locked</code> 版本。</p><p><strong>实现约束</strong>:</p><ul><li>PMM 类添加一个 Spinlock 成员</li><li>添加 <code>alloc_page_locked</code> 和 <code>free_page_locked</code> 私有方法</li><li>公共 <code>alloc_page</code>/<code>free_page</code>/<code>alloc_pages</code>/<code>free_pages</code> 都在入口处获取 Spinlock Guard</li><li><code>alloc_pages</code> 中 count==1 的分支必须调用 <code>_locked</code> 版本</li></ul><p><strong>踩坑预警</strong>: 最容易犯的错误是在 <code>alloc_pages</code> 的 count==1 分支中调用公共 <code>alloc_page</code> 而不是 <code>_locked</code> 版本。编译不会报错，但运行时必然死锁。</p><p><strong>验证</strong>: 分配 8 个页，检查 <code>free_page_count</code> 减少了 8；然后释放这 8 个页，检查计数恢复原值。</p><h3 id="step-2-heap-加锁" tabindex="-1">Step 2: Heap 加锁 <a class="header-anchor" href="#step-2-heap-加锁" aria-label="Permalink to &quot;Step 2: Heap 加锁&quot;">​</a></h3><p><strong>目标</strong>: 保护堆分配器的空闲链表。</p><p><strong>设计思路</strong>: Heap 的 <code>alloc</code> 方法遍历空闲链表做 first-fit 搜索，找到合适的 block 后把它从链表中移除或分割。如果两个线程同时做 alloc，链表指针会被破坏。和 PMM 一样，我们把核心分配逻辑拆成 <code>alloc_locked</code>（内部版本），公共 <code>alloc</code> 只负责获取锁。</p><p>这里有一个额外的复杂性：<code>alloc_locked</code> 如果在空闲链表中找不到合适的 block，会调用 <code>expand</code> 扩展堆，然后递归调用自己重试。这个递归不能走公共 <code>alloc</code>（会死锁），必须走 <code>alloc_locked</code>。</p><p><strong>实现约束</strong>:</p><ul><li>Heap 类添加一个 Spinlock 成员</li><li>将 <code>alloc</code> 的核心逻辑移到 <code>alloc_locked</code> 私有方法</li><li>公共 <code>alloc</code> 获取锁后调用 <code>alloc_locked</code></li><li><code>free</code> 直接在入口处获取锁</li><li><code>alloc_locked</code> 中的递归重试调用自身</li></ul><p><strong>踩坑预警</strong>: Heap 的 expand 操作内部会调用 PMM 的 alloc_page 和 VMM 的 map——这些操作各自有自己的锁，不会与 Heap 的锁冲突（锁的对象不同），所以不存在嵌套死锁问题。但要注意确保 expand 调用的是 PMM 和 VMM 的公共版本（带锁的版本），因为在 Heap 锁的保护下调用这些是安全的。</p><p><strong>验证</strong>: 循环分配 30 个不同大小的内存块，写入特征字节；然后全部释放；重复 5 轮。如果没有崩溃且特征字节正确，说明加锁没有破坏分配逻辑。</p><h3 id="step-3-scheduler-运行队列加锁" tabindex="-1">Step 3: Scheduler 运行队列加锁 <a class="header-anchor" href="#step-3-scheduler-运行队列加锁" aria-label="Permalink to &quot;Step 3: Scheduler 运行队列加锁&quot;">​</a></h3><p><strong>目标</strong>: 保护 RoundRobin 调度器的运行队列。</p><p><strong>设计思路</strong>: 调度器的运行队列是一个环形数组，enqueue/dequeue/pick_next 都在修改它。但调度器有一个特殊要求：<code>tick()</code> 是从时钟中断处理程序中被调用的。中断处理程序的执行是不可预测的——它可能在任何线程执行到任何位置时打断。所以如果线程 A 正在执行 <code>enqueue</code> 持有普通 Guard（没关中断），此时 tick 到来，中断处理程序调用 <code>pick_next</code> 试图获取同一个锁——死锁。</p><p>解决方案：RoundRobin 的三个操作都用 <code>irq_guard()</code> 而不是普通 <code>guard()</code>。这样在操作运行队列之前先禁用中断，中断处理程序不可能打断持锁的代码段。</p><p><strong>实现约束</strong>:</p><ul><li>RoundRobin 类添加一个 Spinlock 成员</li><li><code>enqueue</code>、<code>dequeue</code>、<code>pick_next</code> 入口处获取 <code>irq_guard()</code></li><li><code>tick()</code> 中修改 <code>tick_count_</code> 和 <code>current_slice_</code> 时不需要额外的锁——这些是 atomic 变量</li></ul><p><strong>验证</strong>: 创建 3 个 Task，依次 enqueue，然后 pick_next 验证 FIFO 顺序；dequeue 中间的 task 后再次验证顺序。</p><h3 id="step-4-原子计数器替换" tabindex="-1">Step 4: 原子计数器替换 <a class="header-anchor" href="#step-4-原子计数器替换" aria-label="Permalink to &quot;Step 4: 原子计数器替换&quot;">​</a></h3><p><strong>目标</strong>: 将高频共享计数器从普通变量替换为 <code>std::atomic</code>。</p><p><strong>设计思路</strong>: 有些变量不需要锁的保护，只需要保证读写的原子性。比如 PIT 的 tick 计数器——每次中断加 1，各种地方读取它来做超时判断。用自旋锁保护它代价太大（每个 tick 中断都要获取锁），而 <code>std::atomic</code> 的 <code>fetch_add</code> 在 x86 上会被编译成一条 <code>lock xadd</code> 指令，开销极小。</p><p>同理，<code>Scheduler</code> 的 <code>tick_count_</code> 和 <code>current_slice_</code>，以及 <code>TaskBuilder</code> 的 <code>next_tid</code> 和 <code>next_stack_vaddr</code>——它们只需要原子递增，不需要与其他操作组成原子事务。对于这些变量，<code>MemoryOrder::Relaxed</code> 就够了——我们不在乎操作之间的顺序，只在乎操作本身的原子性。</p><p><strong>实现约束</strong>:</p><ul><li>PIT 的 <code>tick_count_</code> 改为 <code>std::atomic&lt;uint64_t&gt;</code>，递增用 <code>fetch_add(1, Relaxed)</code>，读取用 <code>load(Relaxed)</code></li><li>Scheduler 的 <code>tick_count_</code>/<code>current_slice_</code> 改为 <code>std::atomic&lt;int&gt;</code>，操作同理</li><li>TaskBuilder 的 <code>next_tid</code> 用 <code>fetch_add(1, relaxed)</code> 替代 <code>++</code></li><li>TaskBuilder 的 <code>next_stack_vaddr</code> 用 <code>fetch_add</code> 替代读-加-写序列</li></ul><p><strong>踩坑预警</strong>: <code>next_stack_vaddr</code> 的原始代码是&quot;读取当前值然后加上偏移量&quot;的两步操作。改成 <code>fetch_add</code> 后，返回值就是加之前的旧值——这正好是我们需要的栈起始地址。如果你手动实现&quot;load + add + store&quot;三步，那不是原子的，两个线程可能读到同一个地址。</p><p><strong>验证</strong>: 创建多个 Task，检查它们的 TID 互不相同且递增；检查栈地址互不重叠。</p><h3 id="step-5-文件系统与驱动加锁" tabindex="-1">Step 5: 文件系统与驱动加锁 <a class="header-anchor" href="#step-5-文件系统与驱动加锁" aria-label="Permalink to &quot;Step 5: 文件系统与驱动加锁&quot;">​</a></h3><p><strong>目标</strong>: 保护 FDTable、File offset、VMM、mount 表、键盘缓冲区。</p><p><strong>设计思路</strong>: 这些组件的并发风险相对较低，但在多任务环境下仍然需要保护。</p><p>FDTable 的 <code>alloc</code>/<code>close</code>/<code>get</code> 需要一个 Spinlock：两个线程同时 alloc 可能拿到同一个 slot（double-alloc），或者一个线程 close 了另一个线程正在用的 fd（use-after-free）。加一个 Spinlock 到 FDTable 类中，三个方法入口获取 Guard。</p><p>File 结构体的 <code>offset</code> 字段需要单独保护——多个线程可能通过不同的 fd 指向同一个 File（虽然 Cinux 目前不支持，但 offset_lock_ 为未来做准备），或者在 sys_read/sys_write 中需要保证&quot;读取 offset + 操作 + 更新 offset&quot;的原子性。File 结构体添加一个 <code>mutable Spinlock offset_lock_</code>，sys_read/sys_write/sys_getdents 中用 guard 保护 offset 的读取和更新。</p><p>VMM 的 <code>map</code>/<code>unmap</code> 添加 Spinlock——两个线程同时修改页表结构会导致页表损坏。全局 mount 表 <code>g_mount_table</code> 添加全局 Spinlock <code>g_mount_lock</code>——<code>vfs_mount_add</code>、<code>vfs_mount_remove</code>、<code>vfs_resolve</code> 入口处获取 guard。</p><p>键盘驱动的 <code>poll()</code> 方法使用 InterruptGuard 而非 Spinlock——IRQ1 handler 不获取任何锁（它在中断上下文中直接写入 ring buffer），poll 读取端只需要确保读取时不会被 IRQ1 打断。</p><p><strong>验证</strong>: 打开文件、读取内容、关闭文件——这些操作在之前的 tag 中已经有测试覆盖。加锁后重新运行这些测试，确保功能不受影响。</p><h2 id="构建与运行" tabindex="-1">构建与运行 <a class="header-anchor" href="#构建与运行" aria-label="Permalink to &quot;构建与运行&quot;">​</a></h2><p>完整构建所有测试：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cmake --build build --target big_kernel_test</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>运行 QEMU：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>qemu-system-x86_64 -cdrom build/big_kernel_test.iso -serial stdio -display none</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>预期在串口输出中看到所有已有的测试仍然通过，新增的 PMM 并发测试和 Heap 锁压力测试也通过。</p><h2 id="调试技巧" tabindex="-1">调试技巧 <a class="header-anchor" href="#调试技巧" aria-label="Permalink to &quot;调试技巧&quot;">​</a></h2><p><strong>问题 1: PMM/Heap 死锁</strong> 如果系统在启动时挂住，最可能的原因是 <code>_locked</code> 版本的拆分不完整——某个地方在持锁状态下调用了会再次获取同一个锁的公共方法。用 GDB attach 到 QEMU，查看调用栈：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>gdb build/big_kernel_test</span></span>
<span class="line"><span>(gdb) target remote :1234</span></span>
<span class="line"><span>(gdb) bt</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><strong>问题 2: 中断被永久禁用</strong> 如果系统突然停止响应中断（没有时钟、没有键盘），检查所有 IrqGuard/InterruptGuard 的配对。一个常见的坑是在持锁状态下调用了一个也会获取 IrqGuard 的函数——由于 cli 是幂等的（多次 cli 没关系），问题通常出在析构顺序上。</p><p><strong>问题 3: 串口输出混乱</strong> 如果 kprintf 的输出出现乱序或截断，说明 kprintf 本身可能也需要锁保护。不过 Cinux 的 kprintf 是直接写串口端口，单字节写入是原子的，所以通常不会出问题。如果确实需要保护，可以给 kprintf 加一个 Spinlock。</p><h2 id="本章小结" tabindex="-1">本章小结 <a class="header-anchor" href="#本章小结" aria-label="Permalink to &quot;本章小结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>组件</th><th>保护方式</th><th>原因</th></tr></thead><tbody><tr><td>PMM 位图</td><td>Spinlock Guard + _locked 拆分</td><td>位图查找+设置必须原子</td></tr><tr><td>Heap 空闲链表</td><td>Spinlock Guard + alloc_locked 拆分</td><td>链表遍历+修改必须原子</td></tr><tr><td>Scheduler 运行队列</td><td>Spinlock IrqGuard</td><td>中断上下文也会操作</td></tr><tr><td>PIT/Scheduler/TaskBuilder 计数器</td><td>std::atomic Relaxed</td><td>只需原子递增</td></tr><tr><td>FDTable</td><td>Spinlock Guard</td><td>防止 double-alloc/use-after-free</td></tr><tr><td>File offset</td><td>Spinlock Guard</td><td>读写 offset+更新必须原子</td></tr><tr><td>VMM map/unmap</td><td>Spinlock Guard</td><td>页表修改需要互斥</td></tr><tr><td>Mount 表</td><td>Spinlock Guard</td><td>全局表修改需要互斥</td></tr><tr><td>Keyboard ring buffer</td><td>InterruptGuard</td><td>简单的中断安全即可</td></tr></tbody></table>`,67)])])}const _=o(c,[["render",l]]);export{h as __pageData,_ as default};
